const results = [];
for (const item of $input.all()) {
  const rawText = item.json.text;
  let aiData;
  try {
    const cleaned = rawText.replace(/```json?/g, '').replace(/```/g, '').trim();
    aiData = JSON.parse(cleaned);
  } catch(e) {
    aiData = { detectedIndustry: 'general', brandPersonality: 'professional', visualStyle: 'modern', colorPalette: 'blue and white', emailTone: 'professional', bannerImagePrompt: item.json.Company + ' business banner', emailWritingContext: 'Write a professional cold outreach email.', aiAgentContext: 'Generic business outreach.' };
  }
  const bannerPrompt = aiData.bannerImagePrompt + ' ' + item.json.Company + ' marketing banner';
  const bannerImageUrl = 'https://image.pollinations.ai/prompt/' + encodeURIComponent(bannerPrompt) + '?width=600&height=200&nologo=true&seed=42';
  results.push({ json: { ...item.json, ...aiData, bannerImageUrl } });
}
return results;

